"use strict";parserFactory.registerUrlRule(e=>util.extractHostName(e).endsWith("foxaholic.com"),()=>new FoxaholicParser);class FoxaholicParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.page-content-listing a")].map(e=>util.hyperLinkToChapter(e)).reverse()}extractAuthor(e){let r=e.querySelector("div.author-content");return null===r?super.extractAuthor(e):r.textContent}findChapterTitle(e){let r=e.querySelector("ol.breadcrumb li.active");return null===r?e.querySelector(".item-title"):r.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.summary_image")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.description-summary")]}}